mapper.select:
select config_option_id, config_group_id, option_name, option_value, extra_price, sort_order, is_default, create_time
from sys_product_config_option
where config_option_id = #{configOptionId}

mapper.update:
update sys_product_config_option
option_name = #{optionName}, option_value = #{optionValue}, extra_price = #{extraPrice}, sort_order = #{sortOrder}, is_default = #{isDefault},
where config_option_id = #{configOptionId}
